<script setup lang="ts">
import { computed,onMounted,ref } from 'vue'; import PageHeader from '../components/PageHeader.vue'; import EmptyState from '../components/EmptyState.vue'; import { useAuthStore } from '../stores/auth'; import { getActiveActivity,getLeaderboard } from '../services/api'; import type { LeaderboardRow } from '../types'
const auth=useAuthStore();const rows=ref<LeaderboardRow[]>([]);const sort=ref<'total_loss'|'loss_rate'|'checkin_days'|'streak_days'>('total_loss');const sorted=computed(()=>[...rows.value].sort((a,b)=>b[sort.value]-a[sort.value]));onMounted(async()=>{if(!auth.user)return;const {activity}=await getActiveActivity(auth.user.id);if(activity)rows.value=await getLeaderboard(activity.id)})
</script>
<template><section class="page"><PageHeader eyebrow="TOGETHER" title="全员排行榜"/><van-tabs v-model:active="sort" shrink><van-tab title="减重" name="total_loss"/><van-tab title="比例" name="loss_rate"/><van-tab title="打卡" name="checkin_days"/><van-tab title="连续" name="streak_days"/></van-tabs><div class="card" style="margin-top:12px"><EmptyState v-if="!sorted.length" text="排行榜暂时没有数据"/><article v-for="(r,i) in sorted" :key="r.user_id" class="record row"><div class="row"><span :class="['rank',{top:i<3}]">{{i+1}}</span><div><strong>{{r.nickname}}</strong><div class="muted">{{r.checked_today?'今日已打卡':'今日未打卡'}} · 连续 {{r.streak_days}} 天</div></div></div><div style="text-align:right"><strong>{{sort==='loss_rate'?`${r.loss_rate}%`:sort.includes('days')?`${r[sort]} 天`:`${r.total_loss} kg`}}</strong><div class="muted">{{r.initial_weight}} → {{r.current_weight}} kg</div></div></article></div></section></template>
